+/// Try to fold ceiling division pattern:
+/// (X >> shift) + zext((X & mask) != 0) --> (X + mask) >> shift
+/// where mask = (1 << shift) - 1
+/// This is only safe if X + mask doesn't overflow.
+static Instruction *foldAddToCeilDiv(BinaryOperator &Add, InstCombinerImpl &IC) {
+  Value *Op0 = Add.getOperand(0);
+  Value *Op1 = Add.getOperand(1);
+  
+  Value *X;
+  const APInt *ShiftAmt;
+  
+  // Match: (X >> shift) + ... or ... + (X >> shift)
+  Value *LshrOp;
+  if (match(Op0, m_LShr(m_Value(X), m_APInt(ShiftAmt)))) {
+    LshrOp = Op0;
+  } else if (match(Op1, m_LShr(m_Value(X), m_APInt(ShiftAmt)))) {
+    LshrOp = Op1;
+  } else {
+    return nullptr;
+  }
+
+  unsigned BitWidth = Add.getType()->getScalarSizeInBits();
+  unsigned Shift = ShiftAmt->getZExtValue();
+  if (Shift == 0 || Shift >= BitWidth)
+    return nullptr;
+
+  // mask = (1 << shift) - 1
+  APInt Mask = APInt::getLowBitsSet(BitWidth, Shift);
+
+  // Find the zext operand (the one that's not the lshr)
+  Value *ZextOp = (LshrOp == Op0) ? Op1 : Op0;
+  
+  // Get instruction pointers to check for one-use
+  Instruction *Lshr = dyn_cast<Instruction>(LshrOp);
+  Instruction *Zext = dyn_cast<Instruction>(ZextOp);
+  if (!Lshr || !Zext)
+    return nullptr;
+  
+  // Check that the lshr and zext each have only one use (the add)
+  if (!Lshr->hasOneUse() || !Zext->hasOneUse())
+    return nullptr;
+
+  const APInt *AndMask;
+  CmpPredicate Pred;
+  const APInt *CmpVal;
+  Instruction *ICmpInst;
+  Instruction *AndInst;
+  // Match: zext(icmp pred (X & mask), cmp_val)
+  if (!match(ZextOp, m_ZExt(m_OneUse(m_Instruction(ICmpInst)))))
+    return nullptr;
+  if (!match(ICmpInst, m_OneUse(m_ICmp(Pred, m_OneUse(m_Instruction(AndInst)), m_APInt(CmpVal)))))
+    return nullptr;
+  if (!match(AndInst, m_And(m_Specific(X), m_APInt(AndMask))))
+    return nullptr;
+
+  // Verify the mask matches: mask = (1 << shift) - 1
+  if (*AndMask != Mask)
+    return nullptr;
+
+  // Verify the comparison is checking for non-zero: (X & mask) != 0
+  // The pattern we want is (X & mask) != 0, which is icmp ne ..., 0
+  if (Pred != ICmpInst::ICMP_NE || !CmpVal->isZero())
+    return nullptr;
+
+  // Check that X + mask doesn't overflow. We need either:
+  // 1. The add has both nuw and nsw flags (which proves no overflow in original), OR
+  // 2. X has range info that proves X + mask < 2^bitwidth
+  bool HasOverflowInfo = Add.hasNoUnsignedWrap() && Add.hasNoSignedWrap();
+  if (!HasOverflowInfo) {
+    // Check if X has range info that proves X + mask doesn't overflow
+    const Value *KnownX = X;
+    KnownBits Known = IC.computeKnownBits(KnownX, &Add);
+    APInt MaxX = Known.getMaxValue();
+    if (MaxX.ugt(APInt::getMaxValue(BitWidth) - Mask))
+      return nullptr;  // X + mask could overflow
+  }
+
+  // (X >> shift) + zext((X & mask) != 0) --> (X + mask) >> shift
+  Value *NewAdd = IC.Builder.CreateAdd(X, ConstantInt::get(X->getType(), Mask));
+  return BinaryOperator::CreateLShr(NewAdd, ConstantInt::get(Add.getType(), Shift));
+}
